define({"topics":[{"title":"Harmonic Analyzer","shortdesc":"<p class=\"shortdesc\"> Description of the Harmonic Analyzer component in Schematic Editor, which calculates         amplitude, phase and frequency for the specified harmonics. <\/p>","href":"t-ug002\/References\/harmonic_analyzer.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e5456","topics":[]},{"title":"Phase Difference","shortdesc":"<p class=\"shortdesc\">Description of the Phase Difference component in Schematic Editor, which outputs the         difference between the phases of the input signal in comparison with the reference         signal.<\/p>","href":"t-ug002\/References\/phase_difference.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e5467","topics":[]},{"title":"Positive Negative Zero Power","shortdesc":"<p class=\"shortdesc\"> Description of the Positive Negative Zero Power component in Schematic Editor, which     calculates the power of symmetrical component sequences. <\/p>","href":"t-ug002\/References\/pos_neg_zero_power.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e5478","topics":[]},{"title":"Power Meter","shortdesc":"<p class=\"shortdesc\"> Description of the Power Meter component in Schematic Editor, which computes active and     reactive power (both instantaneous and average), apparent power, and power factor for three phase     systems.<\/p>","href":"t-ug002\/References\/power_meter.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e5489","topics":[]},{"title":"Single Phase Phasor","shortdesc":"<p class=\"shortdesc\">Description of the Single Phase Phasor component in Schematic Editor, which returns     the amplitude and phase of an input signal.<\/p>","href":"t-ug002\/References\/single_phase_phasor.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e5500","topics":[]},{"title":"Single Phase Power Meter","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Description of the Single Phase Power Meter component in Schematic Editor, which     computes active and reactive power of a single-phase circuit.<\/span><\/p>","href":"t-ug002\/References\/single_phase_power_meter.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e5511","topics":[]},{"title":"Symmetrical Components","shortdesc":"<p class=\"shortdesc\"> Description of the Symmetrical Components component in Schematic Editor,      which transforms three-phase systems to sets of symmetrical phasors.<\/p>","href":"t-ug002\/References\/symmetrical_components.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e5523","topics":[]},{"title":"THD (Total Harmonic Distortion) Measurement","shortdesc":"<p class=\"shortdesc\"> Description of the THD Measurement component in Schematic Editor, which calculates the     total harmonic distortion of the input signal.<\/p>","href":"t-ug002\/References\/thd.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e5534","topics":[]},{"title":"Three Phase Phasor","shortdesc":"<p class=\"shortdesc\"> Description of the Three Phase Phasor component in Schematic Editor, which returns the     amplitudes and phases of a three-phase input signal.<\/p>","href":"t-ug002\/References\/three_phase_phasor.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e5545","topics":[]}]});